<script>
{
  const uid = "UID_REPLACE_ME";
  const root = document.getElementById("sa-l-" + uid);
  const raw = document.getElementById("sa-d-" + uid);
  if (root && raw) {
    let items = [];
    const lines = raw.innerText.trim().split('\n');
    lines.forEach((line) => {
        let t = line.trim();
        if(!t) return;
        let m = t.match(/^([a-zA-Z0-9]+)\)\s*(.*)/);
        if(m) items.push({i: m[1], t: m[2]});
        else if(items.length) items[items.length-1].t += "\n" + t;
        else items.push({i: items.length+1, t: t});
    });
    root.innerHTML = items.map(d => 
      `<div class="sa-row" data-txt="${d.t}"><span class="sa-idx">${d.i}</span><div class="sa-txt">${d.t}</div></div>`
    ).join('');
    root.onclick = (e) => {
      const row = e.target.closest('.sa-row');
      if (row && window.triggerSlash) {
        e.preventDefault();
        e.stopPropagation();
        triggerSlash("/setinput " + row.dataset.txt);
      }
    };
  }
}
</script>
